query:
query GetGlobalFonts($isDefault: Boolean) {
  fonts(
    workspaceId: null
    archived: false
    isDefault: $isDefault
    sortBy: {field: name, direction: asc}
  ) {
    ...Font
    __typename
  }
}

fragment Font on Font {
  id
  name
  cssUrl
  fontFiles {
    id
    name
    weight
    isItalic
    fileType
    sourceUrl
    __typename
  }
  workspaceId
  archived
  fontFileCount
  isDefault
  __typename
}
